import{_ as e,o as l,c as a,a7 as d}from"./chunks/framework.C5fSpjcB.js";const c=JSON.parse('{"title":"深海（Aequor）","description":"","frontmatter":{},"headers":[],"relativePath":"ja/realms/aequor.md","filePath":"ja/realms/aequor.md","lastUpdated":1775394001000}'),n={name:"ja/realms/aequor.md"};function r(i,t,s,x,y,g){return l(),a("div",null,[...t[0]||(t[0]=[d('<h1 id="深海-aequor" tabindex="-1">深海（Aequor） <a class="header-anchor" href="#深海-aequor" aria-label="Permalink to &quot;深海（Aequor）&quot;">​</a></h1><p><span class="realm-badge realm-aequor">深海</span></p><p><strong>深海</strong>はクトゥルフ神話における深淵の海洋生物や深きものどもをテーマとした界域です。触腕システムによる自動追撃と持久戦を得意とし、現環境（v2.4）で最強界域の一つです。</p><h2 id="テーマ・世界観" tabindex="-1">テーマ・世界観 <a class="header-anchor" href="#テーマ・世界観" aria-label="Permalink to &quot;テーマ・世界観&quot;">​</a></h2><p>深海界域はクトゥルフやダゴン、インスマスの住人たちに関連する深淵の力を宿す領域です。覚醒体たちは海洋の神秘的な力を操り、敵を圧倒します。</p><h2 id="戦闘スタイル" tabindex="-1">戦闘スタイル <a class="header-anchor" href="#戦闘スタイル" aria-label="Permalink to &quot;戦闘スタイル&quot;">​</a></h2><ul><li><strong>触腕システム</strong> — 戦闘開始時に触腕1体を生成。深海覚醒体がカードをプレイすると追加で触腕を獲得。ターン終了時に前列の敵を自動攻撃。狂気爆発後にも追加攻撃発動</li><li><strong>純深海共鳴</strong> — 純深海編成時、深海精通属性の効果が2倍。戦闘開始時の自動生成触腕数も2倍</li><li><strong>触腕のステータス計算</strong> — 触腕の暴撃率・暴撃ダメージは出撃4体の覚醒体で均分。力量:触腕ダメージ=2:1、界域精通:狂気爆発後追加攻撃回数=2:1</li></ul><h2 id="深海界域の覚醒体" tabindex="-1">深海界域の覚醒体 <a class="header-anchor" href="#深海界域の覚醒体" aria-label="Permalink to &quot;深海界域の覚醒体&quot;">​</a></h2><table tabindex="0"><thead><tr><th style="text-align:left;">覚醒体名</th><th style="text-align:center;">レア</th><th style="text-align:center;">役割</th><th style="text-align:center;">Tier</th><th style="text-align:left;">入手</th></tr></thead><tbody><tr><td style="text-align:left;">图鲁 (Tulu)</td><td style="text-align:center;">SSR</td><td style="text-align:center;">攻撃型</td><td style="text-align:center;">T0</td><td style="text-align:left;">限定</td></tr><tr><td style="text-align:left;">神王·图鲁 (Divine King Tulu)</td><td style="text-align:center;">SSR</td><td style="text-align:center;">攻撃型</td><td style="text-align:center;">—</td><td style="text-align:left;">限定</td></tr><tr><td style="text-align:left;">希莱斯特 (Celeste)</td><td style="text-align:center;">SSR</td><td style="text-align:center;">支援型</td><td style="text-align:center;">T1</td><td style="text-align:left;">常驻</td></tr><tr><td style="text-align:left;">戈利亚 (Goliath)</td><td style="text-align:center;">SSR</td><td style="text-align:center;">防御型</td><td style="text-align:center;">T1</td><td style="text-align:left;">常驻</td></tr><tr><td style="text-align:left;">珊 (Shan)</td><td style="text-align:center;">SSR</td><td style="text-align:center;">副攻撃型</td><td style="text-align:center;">T1</td><td style="text-align:left;">常驻</td></tr><tr><td style="text-align:left;">奥瑞塔 (Aurita)</td><td style="text-align:center;">SSR</td><td style="text-align:center;">攻撃型</td><td style="text-align:center;">T2</td><td style="text-align:left;">無料</td></tr><tr><td style="text-align:left;">凯刻斯 (Caecus)</td><td style="text-align:center;">SSR</td><td style="text-align:center;">副攻撃型</td><td style="text-align:center;">T2</td><td style="text-align:left;">常驻</td></tr><tr><td style="text-align:left;">法洛思 (Faros)</td><td style="text-align:center;">SSR</td><td style="text-align:center;">支援型</td><td style="text-align:center;">T3</td><td style="text-align:left;">常驻</td></tr><tr><td style="text-align:left;">弥利亚姆 (Miryam)</td><td style="text-align:center;">SSR</td><td style="text-align:center;">支援型</td><td style="text-align:center;">—</td><td style="text-align:left;">限定</td></tr><tr><td style="text-align:left;">墨菲 (Murphy)</td><td style="text-align:center;">SSR</td><td style="text-align:center;">防御型</td><td style="text-align:center;">—</td><td style="text-align:left;">唤醒</td></tr><tr><td style="text-align:left;">克珀珊特 (Corposant)</td><td style="text-align:center;">SSR</td><td style="text-align:center;">防御型</td><td style="text-align:center;">—</td><td style="text-align:left;">限定</td></tr><tr><td style="text-align:left;">皮克曼 (Pickman)</td><td style="text-align:center;">SSR</td><td style="text-align:center;">攻撃型</td><td style="text-align:center;">—</td><td style="text-align:left;">限定</td></tr><tr><td style="text-align:left;">诞妄·墨菲 (Murphy: Fauxborn)</td><td style="text-align:center;">SSR</td><td style="text-align:center;">合唱型</td><td style="text-align:center;">—</td><td style="text-align:left;">限定</td></tr></tbody></table><h2 id="おすすめ編成" tabindex="-1">おすすめ編成 <a class="header-anchor" href="#おすすめ編成" aria-label="Permalink to &quot;おすすめ編成&quot;">​</a></h2><div class="tip custom-block"><p class="custom-block-title">TIP</p><p>深海界域はターン終了時の触腕自動追撃が最大の特徴です。この「自動補刀」を理解すれば深海は入門済みです。開荒時に最も快適な界域です。</p></div><h3 id="触腕混傷チーム-定番" tabindex="-1">触腕混傷チーム（定番） <a class="header-anchor" href="#触腕混傷チーム-定番" aria-label="Permalink to &quot;触腕混傷チーム（定番）&quot;">​</a></h3><table tabindex="0"><thead><tr><th style="text-align:center;">枠</th><th style="text-align:left;">キャラ</th><th style="text-align:left;">役割</th></tr></thead><tbody><tr><td style="text-align:center;">メインC</td><td style="text-align:left;">弥利亚姆 (Miryam)</td><td style="text-align:left;">主火力</td></tr><tr><td style="text-align:center;">副C</td><td style="text-align:left;">奥瑞塔 (Aurita)</td><td style="text-align:left;">サブ火力</td></tr><tr><td style="text-align:center;">タンク/回復</td><td style="text-align:left;">凯刻斯 (Caecus)</td><td style="text-align:left;">防御</td></tr><tr><td style="text-align:center;">フレキシブル</td><td style="text-align:left;">墨菲 (Murphy)</td><td style="text-align:left;">弾性枠</td></tr></tbody></table><h3 id="深海ダブルcチーム" tabindex="-1">深海ダブルCチーム <a class="header-anchor" href="#深海ダブルcチーム" aria-label="Permalink to &quot;深海ダブルCチーム&quot;">​</a></h3><table tabindex="0"><thead><tr><th style="text-align:center;">枠</th><th style="text-align:left;">キャラ</th><th style="text-align:left;">役割</th></tr></thead><tbody><tr><td style="text-align:center;">メインC</td><td style="text-align:left;">图鲁 (Tulu)</td><td style="text-align:left;">主火力</td></tr><tr><td style="text-align:center;">副C</td><td style="text-align:left;">奥瑞塔 (Aurita)</td><td style="text-align:left;">サブ火力</td></tr><tr><td style="text-align:center;">回復/復活</td><td style="text-align:left;">希莱斯特 (Celeste)</td><td style="text-align:left;">回復</td></tr><tr><td style="text-align:center;">シールド</td><td style="text-align:left;">珊 (Shan)</td><td style="text-align:left;">護盾</td></tr></tbody></table><h3 id="凯刻斯反撃チーム-高練度向け" tabindex="-1">凯刻斯反撃チーム（高練度向け） <a class="header-anchor" href="#凯刻斯反撃チーム-高練度向け" aria-label="Permalink to &quot;凯刻斯反撃チーム（高練度向け）&quot;">​</a></h3><table tabindex="0"><thead><tr><th style="text-align:center;">枠</th><th style="text-align:left;">キャラ</th><th style="text-align:left;">役割</th></tr></thead><tbody><tr><td style="text-align:center;">反撃コア</td><td style="text-align:left;">凯刻斯 (Caecus)</td><td style="text-align:left;">3覚醒後に防御カードで反撃暴撃</td></tr><tr><td style="text-align:center;">増傷</td><td style="text-align:left;">哈姆林 (Hameln)</td><td style="text-align:left;">増傷サポート</td></tr><tr><td style="text-align:center;">補助</td><td style="text-align:left;">戈利亚 (Goliath)</td><td style="text-align:left;">補助</td></tr><tr><td style="text-align:center;">補助</td><td style="text-align:left;">拉蒙娜 (Ramona)</td><td style="text-align:left;">補助</td></tr></tbody></table><h3 id="sr低コストチーム-新規推奨" tabindex="-1">SR低コストチーム（新規推奨） <a class="header-anchor" href="#sr低コストチーム-新規推奨" aria-label="Permalink to &quot;SR低コストチーム（新規推奨）&quot;">​</a></h3><table tabindex="0"><thead><tr><th style="text-align:center;">枠</th><th style="text-align:left;">キャラ</th><th style="text-align:left;">役割</th></tr></thead><tbody><tr><td style="text-align:center;">反撃/タンク</td><td style="text-align:left;">凯刻斯 (Caecus)</td><td style="text-align:left;">メイン</td></tr><tr><td style="text-align:center;">支援</td><td style="text-align:left;">法洛思 (Faros)</td><td style="text-align:left;">サポート</td></tr><tr><td style="text-align:center;">副C</td><td style="text-align:left;">奥瑞塔 (Aurita)</td><td style="text-align:left;">サブ火力</td></tr><tr><td style="text-align:center;">回復</td><td style="text-align:left;">希莱斯特 (Celeste)</td><td style="text-align:left;">回復</td></tr></tbody></table><p>SR4枚のみでメインストーリー全クリア可能。触腕自動追撃で操作が簡単。</p><h2 id="関連ページ" tabindex="-1">関連ページ <a class="header-anchor" href="#関連ページ" aria-label="Permalink to &quot;関連ページ&quot;">​</a></h2><ul><li><a href="./">界域概要</a></li><li><a href="./chaos.html">混沌（Chaos）</a></li><li><a href="./caro.html">血肉（Caro）</a></li><li><a href="./ultra.html">超維（Ultra）</a></li><li><a href="./../awakeners/team-building.html">編成ガイド</a></li></ul>',22)])])}const o=e(n,[["render",r]]);export{c as __pageData,o as default};
